"use client";

import { useCallback, useEffect, useRef, useState } from "react";
import type {
  PlayerState,
  PlayerControls,
  PlaybackSpeed,
  YtcnPlayerOptions,
} from "@/registry/new-york/use-ytcn-player/types";
import type { QualityLevel } from "@/registry/new-york/use-ytcn-player/quality";
import { loadYouTubeAPI, styleIframe } from "@/registry/new-york/use-ytcn-player/loader";
import {
  enforceQuality,
  parseAvailableQualities,
} from "@/registry/new-york/use-ytcn-player/quality";
import { useFullscreen } from "@/registry/new-york/use-ytcn-player/use-fullscreen";

/* ================================================================ */
/*  Initial state factory                                            */
/* ================================================================ */

function createInitialState(
  options: YtcnPlayerOptions,
  prev?: Partial<PlayerState>
): PlayerState {
  return {
    isPlaying: false,
    isMuted: prev?.isMuted ?? true,
    volume: prev?.volume ?? 100,
    currentTime: 0,
    duration: 0,
    loadedFraction: 0,
    isLoading: true,
    isFullscreen: typeof document !== "undefined" ? !!document.fullscreenElement : false,
    playbackRate: options.defaultSpeed ?? (prev?.playbackRate ?? 1),
    selectedQuality: options.defaultQuality ?? "auto",
    actualQuality: "",
    availableQualities: [],
  };
}

/* ================================================================ */
/*  useYtcnPlayer — Core player lifecycle hook                       */
/* ================================================================ */

/**
 * useYtcnPlayer — The primary hook for managing a YouTube player instance.
 *
 * Handles:
 *   - YouTube API loading (singleton)
 *   - Player creation, destruction, and recreation on quality/videoId change
 *   - State polling (currentTime, buffered, quality) every 250ms
 *   - Stale closure safety via refs for all values consumed in YT callbacks
 *   - Dual-strategy quality enforcement
 *   - Imperative controls (play, pause, seek, volume, speed, quality, fullscreen)
 *
 * Returns containerRef and playerDivRef for DOM attachment, reactive state,
 * and an imperative controls object.
 */
export function useYtcnPlayer(options: YtcnPlayerOptions) {
  const {
    videoId,
    autoplay = false,
    defaultQuality = "auto",
    defaultSpeed = 1,
    startAt = 0,
    onEnd,
    onTimeUpdate,
    onQualityChange,
    onPlaybackRateChange,
  } = options;

  // ── DOM refs ──
  const containerRef = useRef<HTMLDivElement>(null);
  const playerDivRef = useRef<HTMLDivElement>(null);
  const playerRef = useRef<YT.Player | null>(null);

  // ── Stale closure safety refs ──
  // All values consumed inside YT event callbacks (onReady, onStateChange)
  // must be stored in refs and kept in sync. Never rely on closure-captured
  // state inside YT callbacks — they fire asynchronously outside React's
  // render cycle and would capture stale values.
  const volumeRef = useRef(100);
  const isMutedRef = useRef(true);
  const playbackSpeedRef = useRef<PlaybackSpeed>(defaultSpeed);
  const selectedQualityRef = useRef<QualityLevel | "auto">(defaultQuality);

  // Callback refs — avoids re-creating the player when callbacks change
  const onEndRef = useRef(onEnd);
  const onTimeUpdateRef = useRef(onTimeUpdate);
  const onQualityChangeRef = useRef(onQualityChange);
  const onPlaybackRateChangeRef = useRef(onPlaybackRateChange);

  useEffect(() => {
    onEndRef.current = onEnd;
    onTimeUpdateRef.current = onTimeUpdate;
    onQualityChangeRef.current = onQualityChange;
    onPlaybackRateChangeRef.current = onPlaybackRateChange;
  });

  // ── State ──
  const [state, setState] = useState<PlayerState>(() =>
    createInitialState(options)
  );

  // Keep refs in sync so YT callbacks always see the latest values
  useEffect(() => {
    volumeRef.current = state.volume;
    isMutedRef.current = state.isMuted;
    playbackSpeedRef.current = state.playbackRate;
    selectedQualityRef.current = state.selectedQuality;
  }, [state.volume, state.isMuted, state.playbackRate, state.selectedQuality]);

  // ── Fullscreen ──
  const { isFullscreen, toggle: toggleFullscreen } = useFullscreen(containerRef);

  useEffect(() => {
    setState((prev) => ({ ...prev, isFullscreen }));
  }, [isFullscreen]);

  /* ----------------------------------------------------------------
   *  createPlayer
   *
   *  Destroys the current YT.Player instance and recreates it fresh.
   *  Called on initial mount and on quality changes.
   *
   *  After onReady fires we call enforceQuality() (Strategy B) to
   *  lock the quality range via the JS API — this is what makes
   *  low qualities like 360p/240p actually stick.
   * --------------------------------------------------------------- */
  const createPlayer = useCallback(
    (seekSeconds: number, quality: QualityLevel | "auto", wasPlaying: boolean) => {
      if (!videoId || !playerDivRef.current) return;

      // Update ref immediately so onReady closure reads the right value
      selectedQualityRef.current = quality;

      // Destroy existing player
      try {
        playerRef.current?.destroy();
      } catch {
        /* player may already be destroyed */
      }
      playerRef.current = null;

      // YT.Player replaces the target div with an iframe. After destroy()
      // that element is gone — inject a fresh div before each creation.
      const container = playerDivRef.current.parentElement;
      if (!container) return;
      const newDiv = document.createElement("div");
      newDiv.style.width = "100%";
      newDiv.style.height = "100%";
      container.replaceChild(newDiv, playerDivRef.current);
      (playerDivRef as React.MutableRefObject<HTMLDivElement>).current = newDiv;

      setState((prev) => ({ ...prev, isLoading: true }));

      const YT = (window as any).YT;

      // playerVars — Strategy A: vq sets the initial quality hint in the embed URL
      const playerVars: Record<string, any> = {
        controls: 0,
        modestbranding: 1,
        rel: 0,
        autoplay: wasPlaying || autoplay ? 1 : 0,
        mute: 1, // always start muted for autoplay policy; restored in onReady
        enablejsapi: 1,
        origin: window.location.origin,
        playsinline: 1,
        showinfo: 0,
        iv_load_policy: 3,
        disablekb: 0,
        fs: 0,
        cc_load_policy: 0,
        start: Math.floor(seekSeconds),
      };

      if (quality !== "auto") {
        playerVars.vq = quality;
      }

      playerRef.current = new YT.Player(newDiv, {
        videoId,
        playerVars,
        events: {
          onReady: (event: YT.PlayerEvent) => {
            const player = event.target;
            styleIframe(player);

            // Restore volume / mute / speed from refs (always fresh)
            try {
              player.setVolume(volumeRef.current);
              if (!isMutedRef.current) player.unMute();
              if (playbackSpeedRef.current !== 1) {
                player.setPlaybackRate(playbackSpeedRef.current);
              }
            } catch {
              /* player may reject these calls during initialization */
            }

            // Strategy B: lock quality range via JS API
            enforceQuality(player, selectedQualityRef.current);

            setState((prev) => ({
              ...prev,
              isLoading: false,
              duration: player.getDuration() || prev.duration,
              actualQuality:
                (player.getPlaybackQuality() as QualityLevel) || prev.actualQuality,
            }));

            if (wasPlaying) {
              try {
                player.playVideo();
              } catch {
                /* autoplay may be blocked */
              }
            }
          },

          onStateChange: (event: YT.OnStateChangeEvent) => {
            const YT = (window as any).YT;
            const player = event.target;

            switch (event.data) {
              case YT.PlayerState.PLAYING: {
                // Quality list is only available after buffering starts —
                // getAvailableQualityLevels() returns [] in onReady
                const levels: string[] = player.getAvailableQualityLevels() || [];
                const validQualities = parseAvailableQualities(levels);

                // Re-enforce quality on every PLAYING event.
                // YouTube can reset the quality lock after buffering or seeking —
                // calling it here ensures it sticks for the lifetime of playback.
                enforceQuality(player, selectedQualityRef.current);

                setState((prev) => ({
                  ...prev,
                  isPlaying: true,
                  isLoading: false,
                  duration: player.getDuration() || prev.duration,
                  actualQuality:
                    (player.getPlaybackQuality() as QualityLevel) || prev.actualQuality,
                  availableQualities:
                    validQualities.length > 0 ? validQualities : prev.availableQualities,
                }));
                break;
              }

              case YT.PlayerState.PAUSED:
                setState((prev) => ({ ...prev, isPlaying: false }));
                break;

              case YT.PlayerState.BUFFERING:
                setState((prev) => ({ ...prev, isLoading: true }));
                break;

              case YT.PlayerState.ENDED:
                setState((prev) => ({ ...prev, isPlaying: false }));
                onEndRef.current?.();
                break;
            }
          },

          onPlaybackQualityChange: (event: YT.OnPlaybackQualityChangeEvent) => {
            setState((prev) => ({
              ...prev,
              actualQuality: event.data as QualityLevel,
            }));
            onQualityChangeRef.current?.(event.data);
          },

          onPlaybackRateChange: (event: any) => {
            const rate = event.data as PlaybackSpeed;
            setState((prev) => ({ ...prev, playbackRate: rate }));
            onPlaybackRateChangeRef.current?.(rate);
          },

          onError: () => {
            setState((prev) => ({ ...prev, isLoading: false }));
          },
        },
      });
    },
    [videoId, autoplay]
  );

  /* ---- Initialize player on videoId change ---- */
  useEffect(() => {
    if (!videoId) return;

    let isCancelled = false;

    const init = async () => {
      await loadYouTubeAPI();
      if (isCancelled) return;

      setState((prev) => createInitialState(options, prev));
      createPlayer(startAt, defaultQuality, autoplay);
    };

    init();

    return () => {
      isCancelled = true;
      try {
        playerRef.current?.destroy();
      } catch {
        /* player may already be gone */
      }
      playerRef.current = null;
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [videoId]);

  /* ---- Poll for currentTime / buffered / quality ---- */
  useEffect(() => {
    const interval = setInterval(() => {
      const player = playerRef.current;
      if (!player?.getCurrentTime) return;
      try {
        const currentTime = player.getCurrentTime();
        const duration = player.getDuration();
        const loadedFraction = player.getVideoLoadedFraction();

        setState((prev) => ({
          ...prev,
          currentTime,
          duration: duration > 0 ? duration : prev.duration,
          loadedFraction,
        }));

        onTimeUpdateRef.current?.(currentTime, duration);
      } catch {
        /* player may be in a destroyed state between intervals */
      }
    }, 250);

    return () => clearInterval(interval);
  }, []);

  /* ================================================================ */
  /*  Controls — imperative methods exposed to consumers              */
  /* ================================================================ */

  const play = useCallback(() => {
    try {
      playerRef.current?.playVideo();
    } catch {
      /* noop */
    }
  }, []);

  const pause = useCallback(() => {
    try {
      playerRef.current?.pauseVideo();
    } catch {
      /* noop */
    }
  }, []);

  const togglePlay = useCallback(() => {
    const player = playerRef.current;
    if (!player) return;
    try {
      const YT = (window as any).YT;
      if (player.getPlayerState() === YT.PlayerState.PLAYING) {
        player.pauseVideo();
      } else {
        player.playVideo();
      }
    } catch {
      /* noop */
    }
  }, []);

  const seekTo = useCallback((seconds: number) => {
    const player = playerRef.current;
    if (!player) return;
    try {
      player.seekTo(seconds, true);
      setState((prev) => ({ ...prev, currentTime: seconds }));
    } catch {
      /* noop */
    }
  }, []);

  const seekRelative = useCallback((delta: number) => {
    const player = playerRef.current;
    if (!player) return;
    try {
      const current = player.getCurrentTime();
      const duration = player.getDuration();
      const newTime = Math.max(0, Math.min(duration, current + delta));
      player.seekTo(newTime, true);
      setState((prev) => ({ ...prev, currentTime: newTime }));
    } catch {
      /* noop */
    }
  }, []);

  const setVolume = useCallback((vol: number) => {
    const player = playerRef.current;
    if (!player) return;
    try {
      player.setVolume(vol);
      if (vol > 0) {
        player.unMute();
        isMutedRef.current = false;
      } else {
        player.mute();
        isMutedRef.current = true;
      }
      volumeRef.current = vol;
      setState((prev) => ({ ...prev, volume: vol, isMuted: vol === 0 }));
    } catch {
      /* noop */
    }
  }, []);

  const toggleMute = useCallback(() => {
    const player = playerRef.current;
    if (!player) return;
    try {
      if (isMutedRef.current) {
        player.unMute();
        isMutedRef.current = false;
        setState((prev) => ({ ...prev, isMuted: false }));
      } else {
        player.mute();
        isMutedRef.current = true;
        setState((prev) => ({ ...prev, isMuted: true }));
      }
    } catch {
      /* noop */
    }
  }, []);

  const setSpeed = useCallback((rate: PlaybackSpeed) => {
    const player = playerRef.current;
    if (!player) return;
    try {
      player.setPlaybackRate(rate);
      playbackSpeedRef.current = rate;
      setState((prev) => ({ ...prev, playbackRate: rate }));
    } catch {
      /* noop */
    }
  }, []);

  /**
   * setQuality — Changes quality by destroying and recreating the player.
   *
   * YouTube's IFrame API does not reliably apply quality changes to an
   * already-running player. Mid-session setPlaybackQuality() calls are
   * frequently ignored, especially for low qualities. The reliable fix
   * is full player destruction + recreation.
   *
   * Captures currentTime and isPlaying state before destroying, then
   * restores them in the new player's onReady callback.
   */
  const setQuality = useCallback(
    (quality: QualityLevel | "auto") => {
      const player = playerRef.current;
      if (!player || !videoId) return;

      let currentTime = 0;
      let wasPlaying = false;

      try {
        currentTime = player.getCurrentTime() || 0;
        const YT = (window as any).YT;
        wasPlaying = player.getPlayerState() === YT.PlayerState.PLAYING;
      } catch {
        /* noop */
      }

      setState((prev) => ({ ...prev, selectedQuality: quality }));
      createPlayer(currentTime, quality, wasPlaying);
    },
    [videoId, createPlayer]
  );

  // ── Compose controls object ──
  const controls: PlayerControls = {
    play,
    pause,
    togglePlay,
    seekTo,
    seekRelative,
    setVolume,
    toggleMute,
    setSpeed,
    setQuality,
    toggleFullscreen,
  };

  return {
    playerRef,
    containerRef,
    playerDivRef,
    state,
    controls,
  };
}

"use client";

import { useCallback, useEffect, useRef, useState } from "react";

/**
 * useFullscreen — Abstracts the Fullscreen API for a given container ref.
 *
 * Listens for `fullscreenchange` events on `document` rather than the
 * element itself, because the event bubbles and the spec guarantees it
 * fires on `document`. This avoids issues with vendor-prefixed events
 * on older browsers.
 *
 * Returns:
 *   - isFullscreen: whether the element is currently fullscreen
 *   - toggle: call to enter/exit fullscreen
 *   - enter / exit: explicit directional methods
 */
export function useFullscreen(containerRef: React.RefObject<HTMLDivElement | null>) {
  const [isFullscreen, setIsFullscreen] = useState(false);
  const mounted = useRef(true);

  useEffect(() => {
    mounted.current = true;

    const handleChange = () => {
      if (mounted.current) {
        setIsFullscreen(!!document.fullscreenElement);
      }
    };

    document.addEventListener("fullscreenchange", handleChange);
    return () => {
      mounted.current = false;
      document.removeEventListener("fullscreenchange", handleChange);
    };
  }, []);

  const enter = useCallback(() => {
    try {
      containerRef.current?.requestFullscreen();
    } catch {
      /* fullscreen may be denied by browser policy */
    }
  }, [containerRef]);

  const exit = useCallback(() => {
    try {
      if (document.fullscreenElement) document.exitFullscreen();
    } catch {
      /* exit can throw if not in fullscreen */
    }
  }, []);

  const toggle = useCallback(() => {
    if (document.fullscreenElement) {
      exit();
    } else {
      enter();
    }
  }, [enter, exit]);

  return { isFullscreen, toggle, enter, exit };
}

"use client";

import { useEffect, useRef, useState } from "react";
import { loadYouTubeAPI } from "@/registry/new-york/use-ytcn-player/loader";

/**
 * useYouTubeAPI — Loads the YouTube IFrame API once, shared across all players.
 *
 * Uses a module-level singleton promise internally (via loadYouTubeAPI) to
 * ensure exactly one <script> tag is injected regardless of how many
 * components call this hook.
 *
 * Returns { isReady: true } once `YT.Player` is available on `window`.
 */
export function useYouTubeAPI() {
  const [isReady, setIsReady] = useState(false);
  const mounted = useRef(true);

  useEffect(() => {
    mounted.current = true;

    loadYouTubeAPI().then(() => {
      if (mounted.current) setIsReady(true);
    });

    return () => {
      mounted.current = false;
    };
  }, []);

  return { isReady };
}

import type { QualityLevel } from "@/lib/ytcn/quality";

/* ================================================================ */
/*  Playback Speed                                                   */
/* ================================================================ */

export type PlaybackSpeed = 0.25 | 0.5 | 0.75 | 1 | 1.25 | 1.5 | 1.75 | 2;

export const PLAYBACK_SPEEDS: PlaybackSpeed[] = [
  0.25, 0.5, 0.75, 1, 1.25, 1.5, 1.75, 2,
];

/* ================================================================ */
/*  Player State                                                     */
/* ================================================================ */

export interface PlayerState {
  isPlaying: boolean;
  isMuted: boolean;
  volume: number; // 0–100
  currentTime: number; // seconds
  duration: number; // seconds
  loadedFraction: number; // 0–1 buffer progress
  isLoading: boolean;
  isFullscreen: boolean;
  playbackRate: PlaybackSpeed;
  selectedQuality: QualityLevel | "auto";
  actualQuality: QualityLevel | "";
  availableQualities: QualityLevel[];
}

/* ================================================================ */
/*  Player Options                                                   */
/* ================================================================ */

export interface YtcnPlayerOptions {
  /** YouTube video ID (the 11-character string, not a full URL) */
  videoId: string;
  /** Start playback automatically. Browsers require muted audio for this. */
  autoplay?: boolean;
  /** Initial quality hint — applied via both vq and setPlaybackQualityRange */
  defaultQuality?: QualityLevel | "auto";
  /** Initial playback rate */
  defaultSpeed?: PlaybackSpeed;
  /** Resume from this timestamp (seconds) */
  startAt?: number;
  /** Fired when the video reaches its end */
  onEnd?: () => void;
  /** Polled every 250ms during playback */
  onTimeUpdate?: (currentTime: number, duration: number) => void;
  /** Fired when the actual quality level changes */
  onQualityChange?: (quality: string) => void;
  /** Fired when the playback rate changes */
  onPlaybackRateChange?: (rate: number) => void;
}

/* ================================================================ */
/*  Controls Interface                                               */
/* ================================================================ */

export interface PlayerControls {
  play: () => void;
  pause: () => void;
  togglePlay: () => void;
  seekTo: (seconds: number) => void;
  seekRelative: (delta: number) => void;
  setVolume: (vol: number) => void;
  toggleMute: () => void;
  setSpeed: (rate: PlaybackSpeed) => void;
  setQuality: (quality: QualityLevel | "auto") => void;
  toggleFullscreen: () => void;
}

/* ================================================================ */
/*  Keyboard Shortcut Bindings                                       */
/* ================================================================ */

export interface KeyboardBindings {
  play?: string;
  mute?: string;
  fullscreen?: string;
  seekBack?: string;
  seekForward?: string;
}

export const DEFAULT_KEYBOARD_BINDINGS: Required<KeyboardBindings> = {
  play: " ",
  mute: "m",
  fullscreen: "f",
  seekBack: "ArrowLeft",
  seekForward: "ArrowRight",
};

/**
 * loadYouTubeAPI — Singleton YouTube IFrame API loader.
 *
 * Idempotent: multiple calls from different components share a single script
 * load and a single global `onYouTubeIframeAPIReady` callback. Returns a
 * promise that resolves once `YT.Player` is available on window.
 *
 * SSR-safe: guards all `window` access behind a typeof check. In SSR
 * environments (Next.js App Router, Remix, etc.) this returns a resolved
 * promise that does nothing.
 */

let ytApiPromise: Promise<void> | null = null;

export function loadYouTubeAPI(): Promise<void> {
  // SSR guard — no window in server environments
  if (typeof window === "undefined") return Promise.resolve();

  // Already loaded (e.g. user included the script manually)
  if ((window as any).YT?.Player) return Promise.resolve();

  // Singleton: return existing promise if we've already started loading
  if (ytApiPromise) return ytApiPromise;

  ytApiPromise = new Promise<void>((resolve) => {
    (window as any).onYouTubeIframeAPIReady = () => resolve();
    const script = document.createElement("script");
    script.src = "https://www.youtube.com/iframe_api";
    document.head.appendChild(script);
  });

  return ytApiPromise;
}

/**
 * styleIframe — Offsets the YouTube iframe to crop native chrome.
 *
 * YouTube renders its own controls bar (~60px tall) at the bottom of the
 * iframe. Since the iframe is cross-origin, we can't remove these via CSS
 * inside the iframe. Instead we push the iframe 60px above its container
 * and add 120px to its total height, effectively cropping the native bar
 * out of the visible area.
 *
 * The slight horizontal overflow (102% width, -1% left) accounts for
 * YouTube's thin side borders on some resolutions.
 *
 * `pointerEvents: none` ensures any remaining clickable YouTube chrome
 * is blocked — our overlay div handles all user interaction instead.
 */
export function styleIframe(player: YT.Player): void {
  try {
    const iframe = player.getIframe();
    if (iframe) {
      iframe.style.pointerEvents = "none";
      iframe.style.position = "absolute";
      iframe.style.top = "-60px";
      iframe.style.left = "-1%";
      iframe.style.width = "102%";
      iframe.style.height = "calc(100% + 120px)";
    }
  } catch {
    /* player may be in a destroyed state */
  }
}

/**
 * QUALITY_LEVELS — YouTube quality level identifiers mapped to human labels.
 *
 * The `order` field defines sort priority: 0 = highest quality, 7 = lowest.
 * These string keys are the exact values YouTube's IFrame API returns from
 * `getAvailableQualityLevels()` and accepts in `setPlaybackQuality()`.
 */
export const QUALITY_LEVELS = {
  highres: { label: "4K+", order: 0 },
  hd2160: { label: "4K", order: 1 },
  hd1440: { label: "1440p", order: 2 },
  hd1080: { label: "1080p", order: 3 },
  hd720: { label: "720p", order: 4 },
  large: { label: "480p", order: 5 },
  medium: { label: "360p", order: 6 },
  small: { label: "240p", order: 7 },
} as const;

export type QualityLevel = keyof typeof QUALITY_LEVELS;

/**
 * enforceQuality — Dual-strategy quality enforcement.
 *
 * Strategy B (JS API lock): Called after onReady AND on every PLAYING state
 * change. Sets both min and max quality to the same level, forcing YouTube
 * to stay within that exact range. This is what makes lower qualities like
 * 360p/240p actually stick — the vq playerVar (Strategy A, applied at player
 * creation time) alone is not enough for low qualities because YouTube may
 * silently upgrade them if it detects a fast connection.
 *
 * To release the lock and return to adaptive streaming, we set the range
 * from "small" to "highres" which allows YouTube full freedom.
 *
 * Strategy A (vq playerVar) is applied separately at player creation time
 * in the loader — see use-ytcn-player.ts for that path.
 */
export function enforceQuality(
  player: YT.Player | null,
  quality: QualityLevel | "auto"
): void {
  if (!player) return;
  try {
    if (quality === "auto") {
      // Release the quality lock — let YouTube choose freely
      if (typeof (player as any).setPlaybackQualityRange === "function") {
        (player as any).setPlaybackQualityRange("small", "highres");
      }
    } else {
      // Lock both min and max to the same level
      if (typeof (player as any).setPlaybackQualityRange === "function") {
        (player as any).setPlaybackQualityRange(quality, quality);
      }
      // Fallback: also call the single-quality setter if available
      if (typeof (player as any).setPlaybackQuality === "function") {
        (player as any).setPlaybackQuality(quality);
      }
    }
  } catch {
    /* YouTube API calls can throw if the player is in a bad state */
  }
}

/**
 * Filters and sorts raw quality strings from getAvailableQualityLevels()
 * into typed, ordered QualityLevel values.
 */
export function parseAvailableQualities(levels: string[]): QualityLevel[] {
  return levels
    .filter((q): q is QualityLevel => q in QUALITY_LEVELS)
    .sort((a, b) => QUALITY_LEVELS[a].order - QUALITY_LEVELS[b].order);
}

/**
 * formatTime — Converts seconds to a human-readable timestamp string.
 *
 * Returns "H:MM:SS" for videos ≥ 1 hour, "M:SS" otherwise.
 * Handles edge cases: negative values, NaN, Infinity all return "0:00".
 */
export function formatTime(seconds: number): string {
  if (!isFinite(seconds) || seconds < 0) return "0:00";
  const h = Math.floor(seconds / 3600);
  const m = Math.floor((seconds % 3600) / 60);
  const s = Math.floor(seconds % 60);
  if (h > 0) {
    return `${h}:${String(m).padStart(2, "0")}:${String(s).padStart(2, "0")}`;
  }
  return `${m}:${String(s).padStart(2, "0")}`;
}
